/// Pure playback-state contract for [AutoExploreService].
///
/// The service owns timers and controller side effects, but scheduling decisions
/// depend only on these flags. Keeping that contract replayable makes hidden
/// state-order assumptions testable without a wall-clock timer.
class AutoExploreRuntimeState {
  final bool isExploring;
  final bool isPaused;
  final bool isUserInteracting;
  final bool pausedByUserCorrection;

  const AutoExploreRuntimeState({
    required this.isExploring,
    required this.isPaused,
    required this.isUserInteracting,
    required this.pausedByUserCorrection,
  }) : assert(
          !pausedByUserCorrection || (isExploring && !isPaused),
          'pausedByUserCorrection is only valid while auto-explore is armed',
        );

  /// A new auto-zoom leg can start only when auto-explore owns motion.
  ///
  /// Treat [pausedByUserCorrection] as its own motion blocker instead of
  /// relying on [isUserInteracting] to also be true. That keeps release builds
  /// safe if timer callbacks observe a transient flag-order mismatch.
  bool get canScheduleZoomLeg =>
      isExploring && !isPaused && !isUserInteracting && !pausedByUserCorrection;

  /// An in-flight animation must stop as soon as auto-explore loses motion.
  bool get shouldInterruptAnimation => !canScheduleZoomLeg;
}

/// Primary activation behavior for auto-explore controls.
///
/// Keeping this as data prevents the compact button and settings sheet from
/// drifting when auto-explore is armed but temporarily yielded to the user.
enum AutoExplorePrimaryAction {
  startOrResume,
  pause,
  resumeFromTemporaryYield,
}

/// Replayable presentation state for auto-explore controls.
///
/// The service can be exploring while user interaction temporarily owns motion.
/// Controls should not present that state as active auto-motion; otherwise the
/// pause icon/tooltip contradict the user-correction pause badge.
class AutoExploreControlStatus {
  final bool isExploring;
  final bool isPaused;
  final bool pausedByUserCorrection;

  const AutoExploreControlStatus({
    required this.isExploring,
    required this.isPaused,
    required this.pausedByUserCorrection,
  });

  /// True only while auto-explore is actively driving motion.
  bool get isMotionActive =>
      isExploring && !isPaused && !pausedByUserCorrection;

  /// True while auto-explore is armed but temporarily yielded to the user.
  bool get isTemporarilyYielded =>
      isExploring && !isPaused && pausedByUserCorrection;

  /// True when the primary control should present pausing active auto-motion.
  bool get showsPauseAction => isMotionActive;

  /// Replayable primary action for button/sheet activation.
  AutoExplorePrimaryAction get primaryAction {
    if (isMotionActive) return AutoExplorePrimaryAction.pause;
    if (isTemporarilyYielded) {
      return AutoExplorePrimaryAction.resumeFromTemporaryYield;
    }
    return AutoExplorePrimaryAction.startOrResume;
  }

  /// True when tapping the primary control should resume from a temporary yield
  /// instead of toggling into a fully paused state.
  bool get resumesFromTemporaryYield =>
      primaryAction == AutoExplorePrimaryAction.resumeFromTemporaryYield;

  String primaryActionLabel({
    required String startLabel,
    required String pauseLabel,
    required String resumeLabel,
  }) {
    return switch (primaryAction) {
      AutoExplorePrimaryAction.pause => pauseLabel,
      AutoExplorePrimaryAction.resumeFromTemporaryYield => resumeLabel,
      AutoExplorePrimaryAction.startOrResume => startLabel,
    };
  }

  String tooltip({
    required String startLabel,
    required String pauseLabel,
    required String yieldedLabel,
  }) {
    if (isMotionActive) return pauseLabel;
    if (isTemporarilyYielded) return yieldedLabel;
    return startLabel;
  }
}

import 'package:flutter_fractals/features/auto_explore/auto_explore_runtime_state.dart';
import 'package:flutter_test/flutter_test.dart';

void main() {
  group('AutoExploreRuntimeState', () {
    test('allows scheduling only while auto-explore owns motion', () {
      expect(
        const AutoExploreRuntimeState(
          isExploring: true,
          isPaused: false,
          isUserInteracting: false,
          pausedByUserCorrection: false,
        ).canScheduleZoomLeg,
        isTrue,
      );

      for (final state in [
        const AutoExploreRuntimeState(
          isExploring: false,
          isPaused: false,
          isUserInteracting: false,
          pausedByUserCorrection: false,
        ),
        const AutoExploreRuntimeState(
          isExploring: true,
          isPaused: true,
          isUserInteracting: false,
          pausedByUserCorrection: false,
        ),
        const AutoExploreRuntimeState(
          isExploring: true,
          isPaused: false,
          isUserInteracting: true,
          pausedByUserCorrection: true,
        ),
        const AutoExploreRuntimeState(
          isExploring: true,
          isPaused: false,
          isUserInteracting: false,
          pausedByUserCorrection: true,
        ),
      ]) {
        expect(state.canScheduleZoomLeg, isFalse);
        expect(state.shouldInterruptAnimation, isTrue);
      }
    });

    test('keeps user-correction pause as an explicit motion blocker', () {
      final yieldedWithoutInteraction = const AutoExploreRuntimeState(
        isExploring: true,
        isPaused: false,
        isUserInteracting: false,
        pausedByUserCorrection: true,
      );

      expect(yieldedWithoutInteraction.canScheduleZoomLeg, isFalse);
      expect(yieldedWithoutInteraction.shouldInterruptAnimation, isTrue);
    });

    test('characterizes user-correction pause as armed auto-explore only', () {
      expect(
        () => AutoExploreRuntimeState(
          isExploring: true,
          isPaused: true,
          isUserInteracting: false,
          pausedByUserCorrection: true,
        ),
        throwsAssertionError,
      );
      expect(
        () => AutoExploreRuntimeState(
          isExploring: false,
          isPaused: false,
          isUserInteracting: false,
          pausedByUserCorrection: true,
        ),
        throwsAssertionError,
      );
    });
  });
}

import 'package:flutter_fractals/features/auto_explore/auto_explore_control_status.dart';
import 'package:flutter_test/flutter_test.dart';

void main() {
  group('AutoExploreControlStatus', () {
    test('does not present user-correction yield as active auto-motion', () {
      const status = AutoExploreControlStatus(
        isExploring: true,
        isPaused: false,
        pausedByUserCorrection: true,
      );

      expect(status.isMotionActive, isFalse);
      expect(status.isTemporarilyYielded, isTrue);
      expect(
        status.tooltip(
          startLabel: 'Start auto-explore',
          pauseLabel: 'Pause auto-explore',
          yieldedLabel: 'Auto-pilot paused',
        ),
        'Auto-pilot paused',
      );
    });

    test('presents only non-yielding running state as active motion', () {
      const running = AutoExploreControlStatus(
        isExploring: true,
        isPaused: false,
        pausedByUserCorrection: false,
      );
      const yielded = AutoExploreControlStatus(
        isExploring: true,
        isPaused: false,
        pausedByUserCorrection: true,
      );
      const paused = AutoExploreControlStatus(
        isExploring: true,
        isPaused: true,
        pausedByUserCorrection: false,
      );
      const stopped = AutoExploreControlStatus(
        isExploring: false,
        isPaused: false,
        pausedByUserCorrection: false,
      );

      expect(running.isMotionActive, isTrue);
      expect(yielded.isMotionActive, isFalse);
      expect(paused.isMotionActive, isFalse);
      expect(stopped.isMotionActive, isFalse);
      expect(
        running.tooltip(
          startLabel: 'Start auto-explore',
          pauseLabel: 'Pause auto-explore',
          yieldedLabel: 'Auto-pilot paused',
        ),
        'Pause auto-explore',
      );
      expect(
        paused.tooltip(
          startLabel: 'Start auto-explore',
          pauseLabel: 'Pause auto-explore',
          yieldedLabel: 'Auto-pilot paused',
        ),
        'Start auto-explore',
      );
    });

    test('uses active motion, not armed state, for the primary action', () {
      const running = AutoExploreControlStatus(
        isExploring: true,
        isPaused: false,
        pausedByUserCorrection: false,
      );
      const yielded = AutoExploreControlStatus(
        isExploring: true,
        isPaused: false,
        pausedByUserCorrection: true,
      );

      expect(running.showsPauseAction, isTrue);
      expect(yielded.showsPauseAction, isFalse);
    });

    test('routes yielded primary activation to resume instead of pause', () {
      const running = AutoExploreControlStatus(
        isExploring: true,
        isPaused: false,
        pausedByUserCorrection: false,
      );
      const yielded = AutoExploreControlStatus(
        isExploring: true,
        isPaused: false,
        pausedByUserCorrection: true,
      );
      const paused = AutoExploreControlStatus(
        isExploring: true,
        isPaused: true,
        pausedByUserCorrection: false,
      );
      const stopped = AutoExploreControlStatus(
        isExploring: false,
        isPaused: false,
        pausedByUserCorrection: false,
      );

      expect(running.primaryAction, AutoExplorePrimaryAction.pause);
      expect(yielded.primaryAction,
          AutoExplorePrimaryAction.resumeFromTemporaryYield);
      expect(paused.primaryAction, AutoExplorePrimaryAction.startOrResume);
      expect(stopped.primaryAction, AutoExplorePrimaryAction.startOrResume);
      expect(running.resumesFromTemporaryYield, isFalse);
      expect(yielded.resumesFromTemporaryYield, isTrue);
      expect(paused.resumesFromTemporaryYield, isFalse);
    });

    test('labels yielded primary activation as resume, not generic play', () {
      const yielded = AutoExploreControlStatus(
        isExploring: true,
        isPaused: false,
        pausedByUserCorrection: true,
      );
      const paused = AutoExploreControlStatus(
        isExploring: true,
        isPaused: true,
        pausedByUserCorrection: false,
      );
      const running = AutoExploreControlStatus(
        isExploring: true,
        isPaused: false,
        pausedByUserCorrection: false,
      );

      expect(
        yielded.primaryActionLabel(
          startLabel: 'Play',
          pauseLabel: 'Pause',
          resumeLabel: 'Resume',
        ),
        'Resume',
      );
      expect(
        paused.primaryActionLabel(
          startLabel: 'Play',
          pauseLabel: 'Pause',
          resumeLabel: 'Resume',
        ),
        'Play',
      );
      expect(
        running.primaryActionLabel(
          startLabel: 'Play',
          pauseLabel: 'Pause',
          resumeLabel: 'Resume',
        ),
        'Pause',
      );
    });
  });
}

